import{_ as n,C as o,o as s,c as l,E as t,w as r,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Denmark Legal Rights","description":"Legal rights for transgender people in Denmark","frontmatter":{"layout":"doc","title":"Denmark Legal Rights","description":"Legal rights for transgender people in Denmark"},"headers":[],"relativePath":"europe/denmark/legal-rights.md","filePath":"europe/denmark/legal-rights.md","lastUpdated":null}'),h={name:"europe/denmark/legal-rights.md"};function c(g,e,p,m,u,f){const a=o("Badge");return s(),l("div",null,[t(a,{variant:"yellow"},{default:r(()=>[...e[0]||(e[0]=[i("Self-ID since 2014",-1)])]),_:1}),t(a,{variant:"green"},{default:r(()=>[...e[1]||(e[1]=[i("Hate Crime Protections",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="legal-rights-in-denmark" tabindex="-1">Legal Rights in Denmark <a class="header-anchor" href="#legal-rights-in-denmark" aria-label="Permalink to &quot;Legal Rights in Denmark&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Denmark made history in 2014 as the first European country to allow legal gender change based on self-declaration. Adults (18+) can simply submit an online application to the Danish Patient Safety Authority stating they identify as the opposite gender. After a six-month reflection period, the change is confirmed. No medical treatment, diagnosis, surgery, or sterilisation is required.</p><p>For minors aged 15-17, parental consent is needed. Those under 15 require a court order.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><p>Legal name changes are processed through the Danish Civil Registration System (CPR). You can apply through the official website borger.dk. There is no fee, and the process takes 1-2 weeks.</p><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Denmark prohibits discrimination based on gender identity in:</p><ul><li><strong>Employment</strong>: Workplace discrimination is illegal</li><li><strong>Goods and services</strong>: Includes housing and healthcare</li><li><strong>Education</strong>: Protected at all levels</li></ul><p>While gender identity is not explicitly listed in all laws, Danish courts and the Board of Equal Treatment have consistently interpreted existing protections to cover transgender people.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>Gender identity is considered an aggravating factor in hate crime sentencing. The Danish police have dedicated hate crime reporting units. Transphobic hate crimes are tracked and reported by the National Police.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://lgbt.dk/" target="_blank" rel="noreferrer">LGBT+ Denmark</a> — Legal counselling and support</li><li><a href="https://stps.dk/" target="_blank" rel="noreferrer">Danish Patient Safety Authority</a> — Gender recognition applications</li><li><a href="https://www.retsinformation.dk/" target="_blank" rel="noreferrer">Board of Equal Treatment</a> — Discrimination complaints</li></ul>',14))])}const _=n(h,[["render",c]]);export{b as __pageData,_ as default};
